import asyncio
import json
import math
import signal
import time
import uuid
from dataclasses import dataclass, field, asdict
from typing import Dict, List, Optional, Tuple, Any

try:
    import websockets
    from websockets.server import WebSocketServerProtocol
except ImportError:
    raise SystemExit("Please install websockets: pip install websockets")


TICK_RATE = 20
HOST = "0.0.0.0"
PORT = 8765
WORLD_SIZE = 5000.0
PLAYER_SPEED = 300.0
STATE_BROADCAST_INTERVAL = 1.0 / TICK_RATE
MAX_NAME_LEN = 24


@dataclass
class Vec2:
    x: float = 0.0
    y: float = 0.0

    def clamp(self, min_v: float, max_v: float) -> "Vec2":
        self.x = max(min_v, min(max_v, self.x))
        self.y = max(min_v, min(max_v, self.y))
        return self

    def to_dict(self) -> Dict[str, float]:
        return {"x": self.x, "y": self.y}


@dataclass
class Player:
    id: str
    name: str
    position: Vec2
    velocity: Vec2 = field(default_factory=Vec2)
    rotation: float = 0.0
    health: int = 100
    alive: bool = True
    connected: bool = True
    last_input_seq: int = 0
    joined_at: float = field(default_factory=time.time)

    def to_public_dict(self) -> Dict[str, Any]:
        return {
            "id": self.id,
            "name": self.name,
            "position": self.position.to_dict(),
            "velocity": self.velocity.to_dict(),
            "rotation": self.rotation,
            "health": self.health,
            "alive": self.alive,
            "connected": self.connected,
        }


class GameServer:
    def __init__(self, host: str, port: int):
        self.host = host
        self.port = port
        self.players: Dict[str, Player] = {}
        self.connections: Dict[WebSocketServerProtocol, str] = {}
        self.running = True
        self.last_broadcast = 0.0

    async def handler(self, websocket: WebSocketServerProtocol):
        player = self.create_player()
        self.players[player.id] = player
        self.connections[websocket] = player.id

        await self.send(
            websocket,
            {
                "type": "welcome",
                "your_id": player.id,
                "tick_rate": TICK_RATE,
                "world_size": WORLD_SIZE,
            },
        )

        await self.broadcast_event(
            {
                "type": "player_joined",
                "player": player.to_public_dict(),
            }
        )

        try:
            async for raw in websocket:
                await self.handle_message(websocket, raw)
        except Exception:
            pass
        finally:
            await self.disconnect(websocket)

    def create_player(self) -> Player:
        pid = str(uuid.uuid4())
        spawn = Vec2(
            x=(uuid.uuid4().int % int(WORLD_SIZE)),
            y=(uuid.uuid4().int % int(WORLD_SIZE)),
        )
        return Player(
            id=pid,
            name=f"Player-{pid[:8]}",
            position=spawn,
        )

    async def disconnect(self, websocket: WebSocketServerProtocol):
        pid = self.connections.pop(websocket, None)
        if not pid:
            return
        player = self.players.get(pid)
        if player:
            player.connected = False
            await self.broadcast_event(
                {
                    "type": "player_left",
                    "player_id": pid,
                }
            )
            del self.players[pid]

    async def handle_message(self, websocket: WebSocketServerProtocol, raw: str):
        pid = self.connections.get(websocket)
        if not pid:
            return
        player = self.players.get(pid)
        if not player:
            return

        try:
            msg = json.loads(raw)
        except json.JSONDecodeError:
            return

        msg_type = msg.get("type")

        if msg_type == "set_name":
            name = str(msg.get("name", "")).strip()
            if name:
                player.name = name[:MAX_NAME_LEN]
        elif msg_type == "input":
            self.apply_input(player, msg)
        elif msg_type == "state_request":
            await self.send_full_state(websocket)

    def apply_input(self, player: Player, msg: Dict[str, Any]):
        move = msg.get("move", {})
        dx = float(move.get("x", 0.0))
        dy = float(move.get("y", 0.0))
        mag = math.hypot(dx, dy)
        if mag > 1.0:
            dx /= mag
            dy /= mag

        player.velocity.x = dx * PLAYER_SPEED
        player.velocity.y = dy * PLAYER_SPEED
        player.rotation = float(msg.get("rotation", player.rotation))
        player.last_input_seq = int(msg.get("seq", player.last_input_seq))

    async def send(self, websocket: WebSocketServerProtocol, payload: Dict[str, Any]):
        try:
            await websocket.send(json.dumps(payload, separators=(",", ":")))
        except Exception:
            pass

    async def broadcast_event(self, payload: Dict[str, Any]):
        if not self.connections:
            return
        data = json.dumps(payload, separators=(",", ":"))
        dead = []
        for ws in list(self.connections.keys()):
            try:
                await ws.send(data)
            except Exception:
                dead.append(ws)
        for ws in dead:
            await self.disconnect(ws)

    async def send_full_state(self, websocket: WebSocketServerProtocol):
        payload = self.build_full_state()
        await self.send(websocket, payload)

    def build_full_state(self) -> Dict[str, Any]:
        return {
            "type": "full_state",
            "server_time": time.time(),
            "world": {
                "size": WORLD_SIZE,
            },
            "players": [p.to_public_dict() for p in self.players.values()],
        }

    async def game_loop(self):
        dt = 1.0 / TICK_RATE
        while self.running:
            start = time.perf_counter()
            self.update(dt)
            await self.broadcast_state()
            elapsed = time.perf_counter() - start
            await asyncio.sleep(max(0.0, dt - elapsed))

    def update(self, dt: float):
        for player in self.players.values():
            if not player.alive:
                continue
            player.position.x += player.velocity.x * dt
            player.position.y += player.velocity.y * dt
            player.position.clamp(0.0, WORLD_SIZE)

    async def broadcast_state(self):
        payload = self.build_full_state()
        if not self.connections:
            return
        data = json.dumps(payload, separators=(",", ":"))
        dead = []
        for ws in list(self.connections.keys()):
            try:
                await ws.send(data)
            except Exception:
                dead.append(ws)
        for ws in dead:
            await self.disconnect(ws)

    async def start(self):
        async with websockets.serve(
            self.handler,
            self.host,
            self.port,
            max_size=2**20,
            ping_interval=20,
            ping_timeout=20,
        ):
            await self.game_loop()


async def main():
    server = GameServer(HOST, PORT)

    loop = asyncio.get_running_loop()
    stop_event = asyncio.Event()

    def shutdown():
        server.running = False
        stop_event.set()

    for sig in (signal.SIGINT, signal.SIGTERM):
        try:
            loop.add_signal_handler(sig, shutdown)
        except NotImplementedError:
            pass

    server_task = asyncio.create_task(server.start())
    wait_task = asyncio.create_task(stop_event.wait())

    done, pending = await asyncio.wait(
        [server_task, wait_task],
        return_when=asyncio.FIRST_COMPLETED,
    )

    for task in pending:
        task.cancel()

    if server_task in done:
        await server_task


if __name__ == "__main__":
    asyncio.run(main())